CREATE OR REPLACE FUNCTION public.create_custom_activity( p_server_id UUID, p_name TEXT, p_schedule_type TEXT, p_schedule JSONB DEFAULT NULL, p_points_per_participant INTEGER DEFAULT 1, p_party_size INTEGER DEFAULT NULL, p_category TEXT DEFAULT NULL, p_tags TEXT[] DEFAULT '{}', p_image_url TEXT DEFAULT NULL ) RETURNS UUID LANGUAGE plpgsql SECURITY DEFINER AS \$\$ DECLARE v_id UUID; BEGIN INSERT INTO public.activities (server_id, template_id, name, schedule_type, schedule, points_per_participant, party_size, is_enabled, is_custom, category, tags, image_url) VALUES (p_server_id, NULL, p_name, p_schedule_type, p_schedule, p_points_per_participant, p_party_size, true, true, p_category, p_tags, p_image_url) RETURNING id INTO v_id; RETURN v_id; END; \$\$;  
